import "mx-global";
import { Big } from "big.js";

// BEGIN EXTRA CODE
// END EXTRA CODE

/**
 * @param {string} fieldRef
 * @param {string} objectGUID
 * @param {string} scannedString
 * @returns {Promise.<string>}
 */
export async function JS_ModifyDropdownObjectAttribute(fieldRef, objectGUID, scannedString) {
	// BEGIN USER CODE
	return new Promise(function(resolve, reject) {
		mx.data.get({
			guid: objectGUID,
			callback: function(obj) {
				//console.info("Received MxObject with GUID " + obj.getGuid());
				obj.set(fieldRef, scannedString);
				mx.data.commit({
					mxobj: obj, 
					callback: function(commitedObj) {
        				//console.info("Object committed");
						resolve("committed");
    				},
    				error: function(e) {
        				console.warn("Could not commit object:", e);
						resolve("Error");
    				}
				});
    		},
			error: function(e) {
        		console.warn("Could not retrieve MxObject with GUID " + obj.getGuid() + " " , e);
				resolve("Error");
    		}
		});	
	});
	// END USER CODE
}
